SELECT DISTINCT t.* FROM alipay_bill_transactions t
INNER JOIN alipay_bill_imports i ON t.bill_import_id = i.id
INNER JOIN alipay_users au ON i.user_id = au.id
WHERE t.is_archived = false
AND (
    t.person_id IN
    #{id}
    OR au.person_id IN
    #{id}
    OR t.phone_id IN (
        SELECT pp.phone_id FROM person_phone pp
        WHERE pp.person_id IN
        #{id}
    )
)
